      edges: [],
    };
    const legends: IGroup[] = [{ id: 'g1', pattern: '*.tsx', color: '#3B82F6' }];

    const result = buildExportData(data, legends);
    expect(result.legend).toEqual([
      {
        id: 'g1',
        pattern: '*.tsx',
        color: '#3B82F6',
        target: 'node',
        shape2D: undefined,
        shape3D: undefined,
