  it('adds legend ids to edges from edge-targeted legend rules', () => {
    const data: IGraphData = {
      nodes: [
        { id: 'src/App.tsx', label: 'App.tsx', color: '#fff' },
        { id: 'src/lib.ts', label: 'lib.ts', color: '#fff' },
