    graphStore.setState({
      currentCommitSha: 'abc123',
      legends: [{ id: 'g1', pattern: '*.tsx', color: '#3B82F6' }],
      pluginStatuses: [],
      timelineActive: true,
    });

    exportAsJson(data);

    expect(jsonHarness.postMessage).toHaveBeenCalledWith({
      type: 'EXPORT_JSON',
      payload: {
        json: expect.any(String),
        filename: 'codegraphy-graph-2026-03-16T12-34-56.json',
