    expect(result.edges).toEqual([
      {
        id: 'src/index.ts->src/utils.ts#import:static',
        from: 'src/index.ts',
        to: 'src/utils.ts',
        kind: 'import',
        sources: [
          {
            id: 'plugin.typescript:import',
            pluginId: 'plugin.typescript',
            sourceId: 'import',
            label: 'Import',
